import React, { useState } from 'react';
import { NavLink, useNavigate } from 'react-router-dom';
import { useDispatch, useSelector } from 'react-redux';
import { logout } from '../../store/slices/authSlice';

const customerLinks = [
  { to: '/dashboard', label: '🏠 Dashboard' },
  { to: '/transactions', label: '📒 Passbook' },
  { to: '/transfer', label: '↔️ Transfer' },
  { to: '/investments', label: '📈 Investments' },
  { to: '/loans', label: '🏦 Loans' },
  { to: '/chat', label: '💬 Support' },
  { to: '/profile', label: '👤 Profile' }
];

const adminLinks = [
  { to: '/admin/dashboard', label: '🏠 Dashboard' },
  { to: '/admin/customers', label: '👥 Customers' },
  { to: '/admin/accounts', label: '🏦 Accounts' },
  { to: '/admin/loans', label: '📋 Loans' },
  { to: '/admin/chat', label: '💬 Support' }
];

const navStyle = (isActive) => ({
  display: 'block', padding: '10px 16px', margin: '4px 0', borderRadius: 8,
  textDecoration: 'none', fontWeight: isActive ? 700 : 400,
  color: isActive ? '#fff' : '#cbd5e1',
  background: isActive ? '#3b82f6' : 'transparent',
  transition: 'all 0.2s'
});

export default function Sidebar() {
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const { user } = useSelector(s => s.auth);
  const links = user?.role === 'ADMIN' ? adminLinks : customerLinks;
  const [mobileOpen, setMobileOpen] = useState(false);

  const handleLogout = () => {
    dispatch(logout());
    navigate('/login');
  };

  const closeMobile = () => setMobileOpen(false);

  const SidebarContent = () => (
    <div style={{ display: 'flex', flexDirection: 'column', height: '100%' }}>
      <div style={{ marginBottom: 32, padding: '0 8px' }}>
        <div className="d-flex justify-content-between align-items-center">
          <div>
            <h2 style={{ color: '#3b82f6', margin: 0, fontSize: 20 }}>🏦 MyFin Bank</h2>
            <p style={{ color: '#94a3b8', fontSize: 13, margin: '4px 0 0' }}>{user?.name}</p>
            <span style={{ fontSize: 11, color: '#64748b', background: '#334155', padding: '2px 8px', borderRadius: 99 }}>{user?.role}</span>
          </div>
          <button
            className="d-md-none"
            onClick={closeMobile}
            style={{ background: 'none', border: 'none', color: '#94a3b8', fontSize: 22, padding: 0, lineHeight: 1, cursor: 'pointer' }}
            aria-label="Close menu"
          >✕</button>
        </div>
      </div>
      <nav style={{ flex: 1 }}>
        {links.map(l => (
          <NavLink key={l.to} to={l.to} style={({ isActive }) => navStyle(isActive)} onClick={closeMobile}>{l.label}</NavLink>
        ))}
      </nav>
      <button onClick={handleLogout} style={{ marginTop: 16, padding: '10px', borderRadius: 8, border: 'none', background: '#ef4444', color: '#fff', cursor: 'pointer', fontWeight: 600 }}>
        🚪 Logout
      </button>
    </div>
  );

  return (
    <>
      {/* Desktop sidebar (md+) */}
      <div
        className="d-none d-md-flex flex-column"
        style={{ width: 220, minHeight: '100vh', background: '#1e293b', padding: '24px 12px', flexShrink: 0 }}
      >
        <SidebarContent />
      </div>

      {/* Mobile hamburger button */}
      <button
        className="d-md-none"
        onClick={() => setMobileOpen(true)}
        style={{
          position: 'fixed', top: 12, left: 12, zIndex: 1100,
          background: '#1e293b', border: 'none', borderRadius: 8,
          color: '#fff', padding: '8px 12px', fontSize: 20, cursor: 'pointer',
          boxShadow: '0 2px 8px rgba(0,0,0,0.2)'
        }}
        aria-label="Open menu"
      >☰</button>

      {/* Mobile sidebar overlay */}
      {mobileOpen && (
        <div style={{ position: 'fixed', inset: 0, zIndex: 1200, display: 'flex' }} onClick={closeMobile}>
          <div style={{ position: 'absolute', inset: 0, background: 'rgba(0,0,0,0.5)' }} />
          <div
            style={{ position: 'relative', width: 240, minHeight: '100vh', background: '#1e293b', padding: '24px 12px', zIndex: 1, display: 'flex', flexDirection: 'column', overflowY: 'auto' }}
            onClick={e => e.stopPropagation()}
          >
            <SidebarContent />
          </div>
        </div>
      )}
    </>
  );
}
